INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('and', 'op', 61, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "and" can help make a simple sentence.', '"and" 这个词可以帮助组成一个简单句。', '[{"w":"who","def":"who: 相关的动作或关系词","vs":"与 and 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"who\" / \"and\" 的替换练习"},{"w":"because","def":"because: 可帮助扩展句型的基础词","vs":"与 and 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"because\" / \"and\" 的替换练习"},{"w":"but","def":"but: 同一组 Basic English 操作词","vs":"与 and 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"but\" / \"and\" 的替换练习"}]'),
  ('because', 'op', 62, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "because" can help make a simple sentence.', '"because" 这个词可以帮助组成一个简单句。', '[{"w":"and","def":"and: 相关的动作或关系词","vs":"与 because 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"and\" / \"because\" 的替换练习"},{"w":"but","def":"but: 可帮助扩展句型的基础词","vs":"与 because 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"but\" / \"because\" 的替换练习"},{"w":"or","def":"or: 同一组 Basic English 操作词","vs":"与 because 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"or\" / \"because\" 的替换练习"}]'),
  ('but', 'op', 63, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "but" can help make a simple sentence.', '"but" 这个词可以帮助组成一个简单句。', '[{"w":"because","def":"because: 相关的动作或关系词","vs":"与 but 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"because\" / \"but\" 的替换练习"},{"w":"or","def":"or: 可帮助扩展句型的基础词","vs":"与 but 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"or\" / \"but\" 的替换练习"},{"w":"if","def":"if: 同一组 Basic English 操作词","vs":"与 but 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"if\" / \"but\" 的替换练习"}]'),
  ('or', 'op', 64, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "or" can help make a simple sentence.', '"or" 这个词可以帮助组成一个简单句。', '[{"w":"but","def":"but: 相关的动作或关系词","vs":"与 or 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"but\" / \"or\" 的替换练习"},{"w":"if","def":"if: 可帮助扩展句型的基础词","vs":"与 or 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"if\" / \"or\" 的替换练习"},{"w":"though","def":"though: 同一组 Basic English 操作词","vs":"与 or 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"though\" / \"or\" 的替换练习"}]'),
  ('if', 'op', 65, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "if" can help make a simple sentence.', '"if" 这个词可以帮助组成一个简单句。', '[{"w":"or","def":"or: 相关的动作或关系词","vs":"与 if 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"or\" / \"if\" 的替换练习"},{"w":"though","def":"though: 可帮助扩展句型的基础词","vs":"与 if 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"though\" / \"if\" 的替换练习"},{"w":"while","def":"while: 同一组 Basic English 操作词","vs":"与 if 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"while\" / \"if\" 的替换练习"}]');
